    .prev_valid(ex_mem_valid_out),
    .next_ready(mem_wb_ready_out),
    .out_valid(mem_valid),
    .out_ready(mem_ready),
    // 与 BUS 的接口（读通道）
    .lsu_araddr(lsu_araddr),
    .lsu_arvalid(lsu_arvalid),
    .lsu_arready(lsu_arready),
    .lsu_rdata(lsu_rdata),
    .lsu_rvalid(lsu_rvalid),
    // 与 BUS 的接口（写通道）
    .lsu_awaddr(lsu_awaddr),
    .lsu_awvalid(lsu_awvalid),
    .lsu_awready(lsu_awready),
    .lsu_wdata(lsu_wdata),
    .lsu_wstrb(lsu_wstrb),
    .lsu_wvalid(lsu_wvalid),
    .lsu_wready(lsu_wready),
    .lsu_bvalid(lsu_bvalid),
    .lsu_bresp(lsu_bresp),
    .lsu_bready(lsu_bready),
    .lsu_rready(lsu_rready),
    .lsu_rresp(lsu_rresp),
    .access_fault(access_fault)
);

always_comb begin
    mem_wb_in.pc          = ex_mem_out.pc;
    mem_wb_in.alu_result  = ex_mem_out.alu_result; // 透传 ALU 结果 (用于非Load指令写回)
    mem_wb_in.mem_rdata   = lsu_read_data;         // LSU 读出的数据
    mem_wb_in.rd_idx      = ex_mem_out.rd_idx;
    
    // CSR 信息透传
    mem_wb_in.csr_rdata   = ex_mem_out.csr_rdata;             // 假设 CSR 读数据在 EX 阶段已准备好并保持
    mem_wb_in.csr_wdata   = ex_mem_out.csr_wdata;
    mem_wb_in.csr_addr    = ex_mem_out.csr_addr;

    // 控制信号透传 (只剩 WB 包了)
    mem_wb_in.condition_branch = ex_mem_out.condition_branch;
    mem_wb_in.imm         = ex_mem_out.imm;
    mem_wb_in.rs1_data    = ex_mem_out.rs1_data;
    mem_wb_in.access_fault = access_fault;
    mem_wb_in.exc_valid   = ex_mem_out.exc_valid;
    mem_wb_in.ctrl_wb     = ex_mem_out.ctrl_wb;
end

ysyx_25040131_pipcon #(
    .WIDTH($bits(mem_wb_in))
) REG_MEM_WB (
    .clk(clock),
    .reset(reset),
    .flush(flush_mem_wb),

    .data_in(mem_wb_in),
    .valid_in(mem_valid),
    .ready_out(mem_wb_ready_out),

    .data_out(mem_wb_out),
    .valid_out(mem_wb_valid_out),
    .ready_in(1'b1)
);

// ============================================================================
// WBU阶段：写回（GPR写、CSR写）
// ============================================================================
// WBU阶段总是ready（因为是最后阶段）

wire [31:0] wb_final_wdata;

assign wb_final_wdata = (mem_wb_out.ctrl_wb.is_csr) ? mem_wb_out.csr_rdata :
                        (|mem_wb_out.ctrl_wb.read_mem) ? mem_wb_out.mem_rdata :
                        mem_wb_out.alu_result;

// next_pc模块（WBU阶段，组合逻辑）
ysyx_25040131_next_pc NEXT_PC(
    .pcImm_NEXTPC_rs1Imm(mem_wb_out.ctrl_wb.pcImm_NEXTPC_rs1Imm),
    .condition_branch(mem_wb_out.condition_branch),
    .pc(mem_wb_out.pc),           // 使用IFU输出的PC
    .is_mret(mem_wb_out.ctrl_wb.is_mret),
    .mepc(mepc),
    .mtvec(mtvec),
    .exc_valid(mem_wb_out.exc_valid),
    .access_fault(mem_wb_out.access_fault),  // Access Fault 信号
    .offset(mem_wb_out.imm),
    .rs1Data(mem_wb_out.rs1_data), // 使用锁存的 rs1Data，确保跳转目标地址计算正确
    .next_pc(next_pc)
    // 流水线握手信号
);

// GPR读通道（ID阶段）
ysyx_25040131_gpr REG_FILE(
    .rst(reset),
    .clk(clock),
    // 读通道（ID阶段）
    .rs1(rs1),
    .rs2(rs2),
    .read_rs1_data(read_rs1_data),
    .read_rs2_data(read_rs2_data),
    // 写通道（WBU阶段）
    .write_reg(mem_wb_out.ctrl_wb.write_reg),
    .target_reg(mem_wb_out.rd_idx),
    .write_rd_data(wb_final_wdata),
    // 流水线握手信号
    .prev_valid(mem_wb_valid_out),  // MEM阶段有效
    .next_ready(1'b1),   // WBU阶段next_ready（总是1，因为是最后阶段）
    .out_valid(wbu_gpr_valid),  // GPR写操作完成
    .out_ready(wbu_gpr_ready)   // GPR写通道ready
);

// CSR读通道（EXU阶段）
ysyx_25040131_csr u_csr (
    .clk(clock),
    .rst(reset),
    // 读通道（EXU阶段）
    .csr_addr(id_ex_out.csr_addr),
    .csr_rdata(csr_rdata),
    .mtvec_out(mtvec),
    .mepc_out(mepc),
    .idu_valid(id_ex_valid_out),  // IDU输出有效时，CSR读操作立即可用
    .mem_ready(mem_ready),
    .exu_csr_valid(exu_csr_valid),
    // 写通道（WBU阶段）
    .csr_we(mem_wb_out.ctrl_wb.csr_we),
    .csr_wdata(mem_wb_out.csr_wdata),
    // 流水线握手信号
    .prev_valid(mem_wb_valid_out),  // MEM阶段有效
    .next_ready(1'b1),   // WBU阶段next_ready（总是1，因为是最后阶段）
    .out_valid(wbu_csr_valid),  // CSR写操作完成
    .out_ready(wbu_csr_ready),  // CSR写通道ready
    // 异常/中断控制信号
    .exc_valid(mem_wb_out.exc_valid),
    .exc_pc(mem_wb_out.pc),
    .exc_cause(mem_wb_out.exc_cause),
    .exc_tval(mem_wb_out.exc_tval),
    .is_ecall(mem_wb_out.ctrl_wb.is_ecall)
);



// ============================================================================
// 其他模块
// ============================================================================
// MUX选择ALU输入

ysyx_25040131_mux_2 MUX_EX_A(
    .signal(id_ex_out.ctrl_ex.rs1Data_EX_PC),
    .a(id_ex_out.rs1_data),
    .b(id_ex_out.pc),            // 使用IFU输出的PC
    .out(in_alu_a)
);

ysyx_25040131_mux_3 MUX_EX_B(
    .signal(id_ex_out.ctrl_ex.rs2Data_EX_imm32_4),
    .a(id_ex_out.rs2_data),
    .b(id_ex_out.imm),
    .c(32'd4),
    .out(in_alu_b)
);


